// Xianjun jiao. putaoshu@msn.com; xianjun.jiao@imec.be;
`include "board_def.v"
`include "clock_speed.v"
`timescale 1 ns / 1 ps

`include "xpu_pre_def.v"

`ifdef XPU_ENABLE_DBG
`define DEBUG_PREFIX (*mark_debug="true",DONT_TOUCH="TRUE"*)
`else
`define DEBUG_PREFIX
`endif

	module cca #
	(
	  parameter integer RSSI_HALF_DB_WIDTH = 11
	)
	(//need to give answer of ch idle based on: rssi, pkt header (and predicted pkt length), virtual carrier sensing (CTS/RTS)
        input wire clk,
        input wire rstn,

        input wire signed [(RSSI_HALF_DB_WIDTH-1):0] rssi_half_db,
        input wire signed [(RSSI_HALF_DB_WIDTH-1):0] rssi_half_db_th,

        input wire rx_ht_aggr,
        input wire rx_ht_aggr_last,

        input wire demod_is_ongoing,
        input wire tx_rf_is_ongoing,
        input wire cts_toself_rf_is_ongoing,
        input wire ack_cts_is_ongoing,
        input wire fcs_in_strobe,
        input wire [7:0] wait_after_decode_top,

        `DEBUG_PREFIX output wire ch_idle
	);

  wire ch_idle_rssi;

  `DEBUG_PREFIX reg [11:0] wait_after_decode_top_scale;
  `DEBUG_PREFIX reg [11:0] wait_after_decode_count ;
  `DEBUG_PREFIX reg is_counting ; 
  always @(posedge clk) begin
    if (!rstn) begin
      wait_after_decode_top_scale<=0;
      wait_after_decode_count<=0;
      is_counting<=0;
    end else begin
      wait_after_decode_top_scale<=wait_after_decode_top*`COUNT_SCALE;
      if( ( (fcs_in_strobe&&(~rx_ht_aggr)) || (fcs_in_strobe&&rx_ht_aggr_last) ) && (wait_after_decode_top_scale > 0)) begin
        is_counting<=1;
        wait_after_decode_count<=0;
      end else begin
        wait_after_decode_count<=(is_counting? (wait_after_decode_count+1):wait_after_decode_count);
        is_counting<=( (wait_after_decode_count>=wait_after_decode_top_scale)?0:is_counting );
      end
    end
  end

  assign ch_idle_rssi = (is_counting?1:( (rssi_half_db<=rssi_half_db_th) && (~demod_is_ongoing) ));
  assign ch_idle = (ch_idle_rssi&&(~tx_rf_is_ongoing)&&(~cts_toself_rf_is_ongoing)&&(~ack_cts_is_ongoing)); // remove tx_control_state_idle condition, need to separate ch_idle and internal state

	endmodule

// Xianjun jiao. putaoshu@msn.com; xianjun.jiao@imec.be;

`timescale 1 ns / 1 ps

`include "xpu_pre_def.v"

`ifdef XPU_ENABLE_DBG
`define DEBUG_PREFIX (*mark_debug="true",DONT_TOUCH="TRUE"*)
`else
`define DEBUG_PREFIX
`endif

	module rssi #
	(
        parameter integer GPIO_STATUS_WIDTH = 8,
        parameter integer DELAY_CTL_WIDTH = 7,
        parameter integer RSSI_HALF_DB_WIDTH = 11,
        parameter integer IQ_RSSI_HALF_DB_WIDTH = 9,
		parameter integer IQ_DATA_WIDTH	= 16
	)
	(
	    // ad9361 status and ctrl
	    input wire [7:0] gpio_status,

        input wire clk,
        input wire rstn,
        input wire fifo_delay_rstn,

        input wire pkt_header_valid_strobe,

        input wire [(DELAY_CTL_WIDTH-1):0]    delay_ctl,
        `DEBUG_PREFIX input wire [(RSSI_HALF_DB_WIDTH-1):0] rssi_half_db_offset,

	    // Ports to receive IQ from DDC
	    input wire signed [(IQ_DATA_WIDTH-1):0] ddc_i,
        input wire signed [(IQ_DATA_WIDTH-1):0] ddc_q,
        input wire ddc_iq_valid,

        // result outputs
        `DEBUG_PREFIX output wire signed [(IQ_RSSI_HALF_DB_WIDTH-1):0] iq_rssi_half_db,
        `DEBUG_PREFIX output wire iq_rssi_half_db_valid,
        `DEBUG_PREFIX output reg signed [(RSSI_HALF_DB_WIDTH-1):0] rssi_half_db_lock_by_sig_valid,
        `DEBUG_PREFIX output reg [(GPIO_STATUS_WIDTH-1):0] gpio_status_lock_by_sig_valid,
        `DEBUG_PREFIX output reg signed [(RSSI_HALF_DB_WIDTH-1):0] rssi_half_db,
        `DEBUG_PREFIX output reg rssi_half_db_valid,
        `DEBUG_PREFIX output wire [(GPIO_STATUS_WIDTH-1):0] gpio_status_delay,
        `DEBUG_PREFIX output wire gpio_status_delay_valid
	);

    reg fifo_delay_rstn_delay1;
    reg fifo_delay_rstn_delay2;
    reg fifo_delay_rstn_delay3;
    reg fifo_delay_rstn_delay4;

    wire signed [(IQ_DATA_WIDTH-1):0] iq_rssi;
    wire iq_rssi_valid;

    iq_abs_avg # (
        .IQ_DATA_WIDTH(IQ_DATA_WIDTH)
    ) iq_abs_avg_i (
        .clk(clk),
        .rstn(rstn),
        .ddc_i(ddc_i),
        .ddc_q(ddc_q),
        .ddc_iq_valid(ddc_iq_valid),
        .iq_rssi(iq_rssi),
        .iq_rssi_valid(iq_rssi_valid)
    );

    iq_rssi_to_db # (
        .IQ_DATA_WIDTH(IQ_DATA_WIDTH),
        .IQ_RSSI_HALF_DB_WIDTH(IQ_RSSI_HALF_DB_WIDTH)
    ) iq_rssi_to_db_i (
        .clk(clk),
        .rstn(rstn),
        .iq_rssi(iq_rssi),
        .iq_rssi_valid(iq_rssi_valid),
        .iq_rssi_half_db(iq_rssi_half_db), // step size is 0.5dB not 1dB!
        .iq_rssi_half_db_valid(iq_rssi_half_db_valid)
    );

    fifo_sample_delay # (.DATA_WIDTH(GPIO_STATUS_WIDTH), .LOG2_FIFO_DEPTH(DELAY_CTL_WIDTH)) fifo_sample_delay_i (
        .clk(clk),
        .rst(~(fifo_delay_rstn&fifo_delay_rstn_delay1&fifo_delay_rstn_delay2&fifo_delay_rstn_delay3&fifo_delay_rstn_delay4)),
        .delay_ctl(delay_ctl),
        .data_in(gpio_status),
        .data_in_valid(iq_rssi_half_db_valid),
        .data_out(gpio_status_delay),
        .data_out_valid(gpio_status_delay_valid)
    );

    always @( posedge clk )
    if ( rstn == 1'b0 )
    begin
        rssi_half_db <= 0;
        rssi_half_db_valid <= 0;
    end
    else
    begin
        rssi_half_db_valid <= gpio_status_delay_valid;
        if (gpio_status_delay_valid)
        begin
            rssi_half_db <= (rssi_half_db_offset + iq_rssi_half_db - {3'b0, gpio_status_delay[6:0], 1'b0} ); // temp formula
        end
    end

    always @( posedge clk )
    if ( rstn == 1'b0 )
    begin
        fifo_delay_rstn_delay1 <= fifo_delay_rstn;
        fifo_delay_rstn_delay2 <= fifo_delay_rstn;
        fifo_delay_rstn_delay3 <= fifo_delay_rstn;
        fifo_delay_rstn_delay4 <= fifo_delay_rstn;

        rssi_half_db_lock_by_sig_valid <= 0;
        gpio_status_lock_by_sig_valid <= 0;
    end
    else
    begin
        fifo_delay_rstn_delay1 <= fifo_delay_rstn;
        fifo_delay_rstn_delay2 <= fifo_delay_rstn_delay1;
        fifo_delay_rstn_delay3 <= fifo_delay_rstn_delay2;
        fifo_delay_rstn_delay4 <= fifo_delay_rstn_delay3;

        if (pkt_header_valid_strobe)
        begin
            rssi_half_db_lock_by_sig_valid <= rssi_half_db;
            gpio_status_lock_by_sig_valid <= gpio_status;
        end
    end

	endmodule

// Xianjun jiao. putaoshu@msn.com; xianjun.jiao@imec.be;

`timescale 1 ns / 1 ps

	module iq_abs_avg #
	(
		parameter integer IQ_DATA_WIDTH	= 16
	)
	(
        input wire clk,
        input wire rstn,
	    // Ports to receive IQ from DDC
	    input wire signed [(IQ_DATA_WIDTH-1):0] ddc_i,
        input wire signed [(IQ_DATA_WIDTH-1):0] ddc_q,
        input wire ddc_iq_valid,

        // result outputs
        output wire signed [(IQ_DATA_WIDTH-1):0] iq_rssi,
        output wire iq_rssi_valid
	);

    wire signed [(IQ_DATA_WIDTH-1):0] i_dc_rm;
    wire signed [(IQ_DATA_WIDTH-1):0] q_dc_rm;
    wire iq_dc_rm_valid;

    wire signed [(IQ_DATA_WIDTH-1):0] i_abs;
    wire signed [(IQ_DATA_WIDTH-1):0] q_abs;

    // wire signed [(2*IQ_DATA_WIDTH-1):0] iq_abs_mv_avg;
    wire signed [(IQ_DATA_WIDTH-1):0] i_abs_mv_avg;
    wire signed [(IQ_DATA_WIDTH-1):0] q_abs_mv_avg;

    wire iq_abs_avg_ready_internal;

    assign i_abs = (i_dc_rm[IQ_DATA_WIDTH-1]==1'b1)?(-i_dc_rm):i_dc_rm;
    assign q_abs = (q_dc_rm[IQ_DATA_WIDTH-1]==1'b1)?(-q_dc_rm):q_dc_rm;

    // assign iq_rssi = ((iq_abs_mv_avg[(IQ_DATA_WIDTH-1):0]+iq_abs_mv_avg[(2*IQ_DATA_WIDTH-1):IQ_DATA_WIDTH])>>1);
    assign iq_rssi = ((i_abs_mv_avg+q_abs_mv_avg)>>1);

    dc_rm # (
        .DATA_WIDTH(IQ_DATA_WIDTH)
    ) dc_rm_i (
        .clk(clk),
        .rstn(rstn),
        .ddc_i(ddc_i),
        .ddc_q(ddc_q),
        .ddc_iq_valid(ddc_iq_valid),
        .i_dc_rm(i_dc_rm),
        .q_dc_rm(q_dc_rm),
        .iq_dc_rm_valid(iq_dc_rm_valid)
    );

    // mv_avg32 # (
    // ) mv_avg32_i (
    //     .M_AXIS_DATA_tdata(iq_abs_mv_avg),
    //     .M_AXIS_DATA_tvalid(iq_rssi_valid),
    //     .S_AXIS_DATA_tdata({q_abs,i_abs}),
    //     .S_AXIS_DATA_tready(iq_abs_avg_ready_internal),
    //     .S_AXIS_DATA_tvalid(iq_dc_rm_valid),
    //     .aclk(clk),
    //     .aresetn(rstn)
    // );

    mv_avg_dual_ch #(.DATA_WIDTH0(IQ_DATA_WIDTH), .DATA_WIDTH1(IQ_DATA_WIDTH), .LOG2_AVG_LEN(5)) mv_avg32_dual_ch_inst (
        .clk(clk),
        .rstn(rstn),

        .data_in0(i_abs),
        .data_in1(q_abs),
        .data_in_valid(iq_dc_rm_valid),

        .data_out0(i_abs_mv_avg),
        .data_out1(q_abs_mv_avg),
        .data_out_valid(iq_rssi_valid)
    );

    // mv_avg #(.DATA_WIDTH(IQ_DATA_WIDTH), .LOG2_AVG_LEN(5)) mv_avg32_i_inst (
    //     .clk(clk),
    //     .rstn(rstn),

    //     .data_in(i_abs),
    //     .data_in_valid(iq_dc_rm_valid),
    //     .data_out(i_abs_mv_avg),
    //     .data_out_valid(iq_rssi_valid)
    // );
    // mv_avg #(.DATA_WIDTH(IQ_DATA_WIDTH), .LOG2_AVG_LEN(5)) mv_avg32_q_inst (
    //     .clk(clk),
    //     .rstn(rstn),

    //     .data_in(q_abs),
    //     .data_in_valid(iq_dc_rm_valid),
    //     .data_out(q_abs_mv_avg),
    //     .data_out_valid()
    // );

	endmodule

